import{_ as i,o as l,c as a,ag as e}from"./chunks/framework.DtEl18Xn.js";const o="/getbiji-docs-v3/images/IZGGbVMwtoIuyVxwvgTcD8SQnvc.png",s="/getbiji-docs-v3/images/GI47b7kT8oXGk2xUDMpcqqMjnIh.png",p="/getbiji-docs-v3/images/EUaQbxCQzoEY9uxZoOHcta5Sn4D.png",A=JSON.parse('{"title":"语音词库-录音识别更精准","description":"","frontmatter":{"title":"语音词库-录音识别更精准","category":" 如何快速上手记笔记","lastUpdated":"2026-03-14T14:55:27.049Z"},"headers":[],"relativePath":"-如何快速上手记笔记/语音词库-录音识别更精准.md","filePath":"-如何快速上手记笔记/语音词库-录音识别更精准.md"}'),r={name:"-如何快速上手记笔记/语音词库-录音识别更精准.md"};function _(n,t,c,d,u,g){return l(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="语音词库-录音识别更精准" tabindex="-1">语音词库-录音识别更精准 <a class="header-anchor" href="#语音词库-录音识别更精准" aria-label="Permalink to &quot;语音词库-录音识别更精准&quot;">​</a></h1><p>**语音词库——让 AI 准确听懂每一个专业词 **</p><p>添加你常用的专有名词、人名、术语，录音转写不再写错</p><p>录音转写时，专有名词、人名、行业术语最容易被误识别——&quot;柳比歇夫&quot;可能变成&quot;刘比谢夫&quot;，&quot;GetSeed&quot;可能变成&quot;get seed&quot;。</p><p>语音词库帮你解决这个问题：把你常用的词提前告诉 AI，录音转写时 AI 就会优先识别这些词，大幅提升准确率。</p><p><strong>适用场景</strong></p><ul><li>行业术语：金融、法律、医疗、科技等领域的专业词汇，避免转写时被识别成同音别字</li><li>人名识别：同事、客户、合作伙伴的姓名，特别是生僻字或容易混淆的名字</li><li>产品/品牌名：公司内部产品代号、品牌名称、项目代号等专有名词</li><li>外来词汇：英文缩写、外语人名、中英混用的表达，帮助 AI 正确识别</li><li>学术场景：课程名称、学术概念、文献中的特定术语</li></ul><p><strong>核心功能</strong></p><ul><li>智能推荐热词：AI 基于你已有的笔记内容，自动分析并推荐高频出现但可能识别不准的词汇，一键添加即可</li><li>自定义添加：手动创建并添加你需要的热词，输入正确写法，AI 在后续转写时会优先匹配</li><li>提升识别率：词库中的词会在语音识别时被加权，遇到同音词时优先识别为你设定的正确写法</li></ul><h1 id="app端——使用说明" tabindex="-1">APP端——使用说明 <a class="header-anchor" href="#app端——使用说明" aria-label="Permalink to &quot;APP端——使用说明&quot;">​</a></h1><ol><li>打开 App，点首页右上角菜单，点头像进入「我的账号」页面，在常用操作区域点击「语音词库」</li><li>进入词库页面后，可以看到两个区域：AI 智能推荐的热词和自定义词库</li><li>智能推荐：AI 会基于你的笔记内容分析出高频热词，点击即可一键添加到词库</li><li>自定义添加：输入你需要的词汇（如人名、术语、品牌名），保存后即刻生效</li><li>设置完成后无需其他操作，后续录音转写时 AI 会自动应用词库，优先识别你添加的词汇</li><li>录音中，点击右上角设置按钮，也可进入语音词库 <img src="'+o+'" alt=""></li></ol><p><img src="'+s+'" alt=""></p><p><img src="'+p+'" alt=""></p>',13)])])}const I=i(r,[["render",_]]);export{A as __pageData,I as default};
